
#include "svg_helper.h"
int main(){string stem="13_recursive_merge_sort",title="13 Recursive Merge Sort"; vector<string> stages={"Split [5,3,8,1,4,7]","Split left and right halves","Singleton leaves reached","Merge pairs","Merge larger halves","Final merge sorted array"}; vector<string> f={"divide array into halves","recursively sort each half","merge sorted halves","stable O(n log n) process"}; for(int k=0;k<stages.size();++k){int W=1140,H=680; string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / "+to_string(stages.size())+" - split tree then merge back"); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Recursive merge sort: divide tree on top, merge results upward",17,"#123","700"); vector<string> nodes={"5 3 8 1 4 7","5 3 8","1 4 7","5","3 8","1","4 7","3","8","4","7"}; vector<pair<int,int>> pos={{250,190},{150,270},{380,270},{90,350},{210,350},{350,350},{470,350},{185,430},{255,430},{445,430},{505,430}}; for(int i=0;i<nodes.size();++i){bool show=(k>=0 && i==0)||(k>=1 && i<=2)||(k>=2 && i<=10); if(show){string fill=(k>=3 && i>=3)?"#dcfce7":"#e0f2fe"; s+=box(pos[i].first,pos[i].second,90,42,fill,"#64748b"); s+=T(pos[i].first+10,pos[i].second+27,nodes[i],14,"#123","700");}} vector<pair<int,int>> edges={{0,1},{0,2},{1,3},{1,4},{2,5},{2,6},{4,7},{4,8},{6,9},{6,10}}; for(auto [u,v]:edges) if(k>=1) s+=arrow(pos[u].first+45,pos[u].second+42,pos[v].first+45,pos[v].second,"#64748b",2); if(k>=4){s+=arrow(240,520,350,520,"#d92d27",4); s+=T(250,555,"merge upward",16,"#b91c1c","700");} if(k==5) s+=arr(vector<int>{1,3,4,5,7,8},150,575,{},set<int>{0,1,2,3,4,5}); s+=sidebar(k+1,stages.size(),f)+footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG());}}
